import React from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { useMT5 } from '../context/MT5Context';
import './Navbar.css';

function Navbar() {
  const { t, i18n } = useTranslation();
  const { isConnected, accountInfo } = useMT5();

  const changeLanguage = (lng) => {
    i18n.changeLanguage(lng);
    document.documentElement.dir = lng === 'ar' ? 'rtl' : 'ltr';
  };

  return (
    <nav className="navbar">
      <div className="navbar-brand">
        <Link to="/">{t('appTitle')}</Link>
      </div>
      <div className="navbar-links">
        <Link to="/">{t('nav.dashboard')}</Link>
        <Link to="/mt5-connection">{t('nav.mt5Connection')}</Link>
        <Link to="/chart">{t('nav.goldChart')}</Link>
        <Link to="/positions">{t('nav.openPositions')}</Link>
        <Link to="/history">{t('nav.tradeHistory')}</Link>
        <Link to="/strategy">{t('nav.strategySettings')}</Link>
        <Link to="/logs">{t('nav.logs')}</Link>
        <Link to="/debug">{t('nav.debugConsole')}</Link>
      </div>
      <div className="mt5-status">
        {isConnected ? (
          <div className="status-connected">
            <span className="status-dot"></span>
            {accountInfo?.login ? `Connected: ${accountInfo.login}` : 'Connected'}
          </div>
        ) : (
          <div className="status-disconnected">
            <span className="status-dot"></span>
            Disconnected
          </div>
        )}
      </div>
      <div className="language-switcher">
        <button 
          className={i18n.language === 'en' ? 'active' : ''}
          onClick={() => changeLanguage('en')}
        >
          EN
        </button>
        <button 
          className={i18n.language === 'ar' ? 'active' : ''}
          onClick={() => changeLanguage('ar')}
        >
          عربي
        </button>
      </div>
    </nav>
  );
}

export default Navbar;
